import { ShuttleOrder } from '../types'
import { DateTime } from 'luxon'
export const useShuttleOrders = () => {
    const getStartTime = (order: ShuttleOrder) => {
        const startTime = DateTime.fromMillis(Number(order.orderPlanShuttle.time), { zone: 'Asia/Ho_Chi_Minh' })
        return startTime.toFormat('HH:mm')
    }
    return {
        getStartTime,
    }
}
