<script setup lang="ts">
import { ref } from 'vue'
import { Base64 } from 'js-base64'
import OrdersTable from './widgets/OrdersTable.vue'
import OrderDetailForm from './widgets/OrderDetailForm.vue'
import OrderShuttleDetailForm from './widgets/OrderShuttleDetailForm.vue'
import OrderCharterDetailForm from './widgets/OrderCharterDetailForm.vue'
import OrderMassageDetailForm from './widgets/OrderMassageDetailForm.vue'
import OrderTutorDetailForm from './widgets/OrderTutorDetailForm.vue'
import OrderQuoteDetailForm from './widgets/OrderQuoteDetailForm.vue'
import { Order, VnOrder } from './types'
import { useOrders } from './composables/useOrders'
import { useToast, VaModal } from 'vuestic-ui'
import { ServiceCategoryBackend } from './types'
const showOrderModal = ref(false)
const showQuoteModal = ref(false)
const { orders, isLoading, filters, sorting, pagination, ...ordersApi } = useOrders()

const focusedOrder = ref<VnOrder | null>(null)

const showEditOrderModal = (order: VnOrder) => {
    focusedOrder.value = order
    showOrderModal.value = true
}

const showQuoteOrderModal = () => {
    showQuoteModal.value = true
}

const { init: notify } = useToast()

// 自訂訂單表單資料
const quoteForm = ref({
    amount: '',
    note: '',
    remark: '',
})

// 生成的 URL
const generatedUrl = ref('')

// 產生 URL
const onCreateQuoteOrder = async () => {
    try {
        // 建立預填資料
        const prefillData = {
            amount: Number(quoteForm.value.amount) || 0,
            note: quoteForm.value.note,
            remark: quoteForm.value.remark,
        }

        // JSON 字串化
        const jsonString = JSON.stringify(prefillData)

        // Base64URL 編碼
        const encodedString = Base64.encodeURI(jsonString)

        // 產生完整 URL
        const baseUrl = `${import.meta.env.VITE_FRONT_PAGE_DOMAIN}order/quote`
        const finalUrl = `${baseUrl}?d=${encodedString}`

        // 設定生成的 URL
        generatedUrl.value = finalUrl

        notify({
            message: 'URL 已生成',
            color: 'success',
        })
    } catch (error) {
        notify({
            message: '生成 URL 失敗',
            color: 'danger',
        })
    }
}

// 複製 URL 到剪貼簿
const copyUrl = async () => {
    try {
        await navigator.clipboard.writeText(generatedUrl.value)
        notify({
            message: 'URL 已複製到剪貼簿',
            color: 'success',
        })
    } catch (error) {
        notify({
            message: '複製失敗',
            color: 'danger',
        })
    }
}

const onUserSaved = async () => {
    // if (focusedOrder.value) {
    //     await ordersApi.update(user)
    //     notify({
    //         message: `${user.id} has been updated`,
    //         color: 'success',
    //     })
    // } else {
    //     ordersApi.add(user)
    //     notify({
    //         message: `${user.id} has been created`,
    //         color: 'success',
    //     })
    // }
    ordersApi.fetch()
}

const onUserDelete = async (order: Order) => {
    await ordersApi.remove(order)
    notify({
        message: `${order.id} has been deleted`,
        color: 'success',
    })
}

const editFormRef = ref()

// const { confirm } = useModal()

const beforeEditFormModalClose = async (hide: () => unknown) => {
    // if (editFormRef.value.isFormHasUnsavedChanges) {
    //   const agreed = await confirm({
    //     maxWidth: '380px',
    //     message: 'Form has unsaved changes. Are you sure you want to close it?',
    //     size: 'small',
    //   })
    //   if (agreed) {
    //     hide()
    //   }
    // } else {
    //   hide()
    // }
    hide()
}
</script>

<template>
    <h1 class="page-title">訂單管理</h1>

    <VaCard>
        <VaCardContent>
            <div class="flex flex-col md:flex-row gap-2 mb-2 justify-between">
                <div class="flex flex-col md:flex-row gap-2 justify-start">
                    <VaButtonToggle
                        v-model="filters.isActive"
                        color="background-element"
                        border-color="background-element"
                        :options="[
                            { label: '訂單', value: true },
                            { label: '草稿', value: false },
                        ]"
                    />
                    <VaInput v-model="filters.search" placeholder="Search">
                        <template #prependInner>
                            <VaIcon name="search" color="secondary" size="small" />
                        </template>
                    </VaInput>
                </div>
                <VaButton @click="showQuoteOrderModal">新增自訂訂單</VaButton>
            </div>

            <OrdersTable
                v-model:sort-by="sorting.sortBy"
                v-model:sorting-order="sorting.sortingOrder"
                :orders="orders"
                :loading="isLoading"
                :pagination="pagination"
                @editOrder="showEditOrderModal"
                @deleteUser="onUserDelete"
            />
        </VaCardContent>
    </VaCard>

    <VaModal
        v-slot="{ cancel, ok }"
        v-model="showOrderModal"
        size="small"
        mobile-fullscreen
        close-button
        hide-default-actions
        :before-cancel="beforeEditFormModalClose"
    >
        <h1 class="va-h5">訂單編號 {{ focusedOrder!.id }}</h1>
        <OrderDetailForm
            v-if="focusedOrder!.type === ServiceCategoryBackend.ESCORT"
            ref="editFormRef"
            :order="focusedOrder!"
            save-button-label="儲存"
            @close="cancel"
            @save="
                () => {
                    onUserSaved()
                    ok()
                }
            "
        />
        <OrderMassageDetailForm
            v-if="focusedOrder!.type === ServiceCategoryBackend.MASSAGE"
            ref="editFormRef"
            :order="focusedOrder!"
            save-button-label="儲存"
            @close="cancel"
            @save="
                () => {
                    onUserSaved()
                    ok()
                }
            "
        />
        <OrderShuttleDetailForm
            v-else-if="focusedOrder!.type === ServiceCategoryBackend.SHUTTLE"
            ref="editFormRef"
            :order="focusedOrder!"
            save-button-label="儲存"
            @close="cancel"
            @save="
                () => {
                    onUserSaved()
                    ok()
                }
            "
        />
        <OrderCharterDetailForm
            v-else-if="focusedOrder!.type === ServiceCategoryBackend.CHARTER"
            ref="editFormRef"
            :order="focusedOrder!"
            save-button-label="儲存"
            @close="cancel"
            @save="
                () => {
                    onUserSaved()
                    ok()
                }
            "
        />
        <OrderTutorDetailForm
            v-else-if="focusedOrder!.type === ServiceCategoryBackend.TUTOR"
            ref="editFormRef"
            :order="focusedOrder!"
            save-button-label="儲存"
            @close="cancel"
            @save="
                () => {
                    onUserSaved()
                    ok()
                }
            "
        />
        <OrderQuoteDetailForm
            v-else-if="focusedOrder!.type === ServiceCategoryBackend.QUOTE"
            ref="editFormRef"
            :order="focusedOrder!"
            save-button-label="儲存"
            @close="cancel"
            @save="
                () => {
                    onUserSaved()
                    ok()
                }
            "
        />
        <div v-else>未知的訂單類型</div>
    </VaModal>

    <VaModal v-model="showQuoteModal" size="small" mobile-fullscreen close-button hide-default-actions>
        <h1 class="va-h5">自訂訂單</h1>
        <VaForm
            v-slot="{ isValid }"
            ref="quote-form"
            class="flex-col justify-start items-start gap-4 inline-flex w-full"
        >
            <div class="self-stretch flex-col justify-start items-start gap-4 flex">
                <VaDivider class="w-full" orientation="left"><span class="px-2">訂單資訊</span></VaDivider>
                <div class="flex gap-4 flex-col sm:flex-row w-full">
                    <VaInput
                        v-model="quoteForm.amount"
                        label="付款金額"
                        class="w-full"
                        name="amount"
                        type="number"
                        placeholder="請輸入金額"
                    />
                </div>
                <VaTextarea
                    v-model="quoteForm.note"
                    label="訂單備註(用戶端)"
                    class="w-full"
                    name="note"
                    placeholder="請輸入用戶端訂單備註"
                />
                <VaTextarea
                    v-model="quoteForm.remark"
                    label="筆記(管理員)"
                    class="w-full"
                    name="remark"
                    placeholder="請輸入管理員筆記"
                />
                <div
                    class="flex gap-2 flex-col-reverse items-stretch justify-end w-full sm:flex-row sm:items-center mt-4"
                >
                    <VaButton preset="secondary" color="secondary" @click="showQuoteModal = false">取消</VaButton>
                    <VaButton :disabled="!isValid" @click="onCreateQuoteOrder">產生 URL</VaButton>
                </div>

                <!-- URL 顯示區域 -->
                <div v-if="generatedUrl" class="w-full mt-4">
                    <VaDivider class="w-full" orientation="left"><span class="px-2">生成的 URL</span></VaDivider>
                    <div class="flex gap-2 w-full">
                        <VaInput v-model="generatedUrl" label="完整 URL" class="w-full" readonly preset="solid" />
                        <VaButton class="flex-shrink-0 self-end" color="primary" icon="content_copy" @click="copyUrl">
                            複製
                        </VaButton>
                    </div>
                </div>
            </div>
        </VaForm>
    </VaModal>
</template>
