<!-- eslint-disable vue/script-indent -->
<script setup lang="ts">
import { defineVaDataTableColumns, useModal } from 'vuestic-ui'
import {
    OrderWithPlanEscort,
    Order,
    ServiceCategoryBackend,
    OrderStatus,
    PaymentType,
    Payment,
    PaymentStatus,
    OrderManualOperationStatus,
    VnOrder,
    OrderType,
} from '../types'
import { PropType, computed, toRef } from 'vue'
import { Pagination, Sorting } from '../../../data/pages/orders'
import { useVModel } from '@vueuse/core'
import { useOrders } from '../composables/useOrders'
import { useFormat } from '../../../composables/useFormat'
const { categorys } = useOrders()
const { formatDateTime, formatDateTimeV } = useFormat()
const { getServiceDate, getServiceDuring } = useOrders()
const columns = defineVaDataTableColumns([
    { label: '訂單編號', key: 'id', sortable: true },
    { label: '訂單狀態', key: 'status', sortable: true },
    { label: '付款狀態', key: 'payment', sortable: false },
    { label: '操作狀態', key: 'manualOperationStatus', sortable: false },
    { label: '下訂時間', key: 'createdAt', sortable: true },
    { label: '訂購人', key: 'username', sortable: true },
    { label: '訂購項目', key: 'type', sortable: true },
    { label: '訂購方案', key: 'planName', sortable: true },
    { label: '行程時段', key: 'startTime', sortable: true },
    { label: '已支付訂金', key: 'deposit', sortable: true },
    { label: '尾款(VND)', key: 'finalPayment', sortable: true },
    { label: ' ', key: 'actions', align: 'right' },
])
const planIdNameMap: { [key in number]: string } = {
    1: '東方小巴黎',
    2: '華燈夜生活',
    3: '西貢河船宴',
    4: '韓式桑拿趣',
}
const shuttlePlanIdNameMap: { [key in number]: string } = {
    1: '機場-市區',
    2: '市區-機場',
}
const props = defineProps({
    orders: {
        type: Array as PropType<VnOrder[]>,
        required: true,
    },
    loading: { type: Boolean, default: false },
    pagination: { type: Object as PropType<Pagination>, required: true },
    sortBy: { type: String as PropType<Sorting['sortBy']>, required: true },
    sortingOrder: { type: String as PropType<Sorting['sortingOrder']>, required: true },
})

const emit = defineEmits<{
    (event: 'edit-order', order: Order): void
    (event: 'delete-order', order: Order): void
    (event: 'update:sortBy', sortBy: Sorting['sortBy']): void
    (event: 'update:sortingOrder', sortingOrder: Sorting['sortingOrder']): void
}>()

const orders = toRef(props, 'orders')
const sortByVModel = useVModel(props, 'sortBy', emit)
const sortingOrderVModel = useVModel(props, 'sortingOrder', emit)

const statusColors: Record<OrderStatus, string> = {
    initial: 'secondary',
    payment: 'warning',
    payment_fail: 'warning',
    completed: 'success',
    cancel: 'warning',
    cancel_completed: 'secondary',
}

const statusTexts: Record<OrderStatus, string> = {
    initial: '草稿',
    payment: '未付款',
    payment_fail: '付款失敗',
    completed: '已完成',
    cancel: '訂單取消',
    cancel_completed: '已取消',
}

const manualOperationStatusTexts: Record<OrderManualOperationStatus, string> = {
    [OrderManualOperationStatus.PENDING]: '待處理',
    [OrderManualOperationStatus.PROCESSED]: '已處理',
}
const manualOperationStatusColors: Record<OrderManualOperationStatus, string> = {
    [OrderManualOperationStatus.PENDING]: 'warning',
    [OrderManualOperationStatus.PROCESSED]: 'success',
}

const totalPages = computed(() => Math.ceil(props.pagination.total / props.pagination.perPage))

const { confirm } = useModal()

const onUserDelete = async (user: Order) => {
    const agreed = await confirm({
        title: 'Delete user',
        message: `Are you sure you want to delete ${user.id}?`,
        okText: 'Delete',
        cancelText: 'Cancel',
        size: 'small',
        maxWidth: '380px',
    })

    if (agreed) {
        emit('delete-order', user)
    }
}
const getDepositAmount = (order: OrderWithPlanEscort) => {
    const payments = order.payment || []
    if (payments.length === 0) {
        return 0
    }
    const deposit = payments.find((payment) => payment.type === PaymentType.ECPAY_PAYMENT)
    if (deposit) {
        return deposit.amount
    }
    return 0
}
const formatToK = (num: number): string => {
    if (num < 1000) return num.toString()
    return `${Math.floor(num / 1000)}K`
}
const getFinalPayment = (order: VnOrder) => {
    switch (order.type) {
        case OrderType.PlanShuttle:
            return formatToK(
                order.orderPlanShuttleSnapshot.totalAmount - order.orderPlanShuttleSnapshot.prePaymentAmount,
            )
        case OrderType.PlanCharter:
            return formatToK(
                order.orderPlanCharterSnapshot.totalAmount - order.orderPlanCharterSnapshot.prePaymentAmount,
            )
        case OrderType.PlanEscort:
            return formatToK(order.orderPlanEscortSnapshot.totalAmount - order.orderPlanEscortSnapshot.prePaymentAmount)
        case OrderType.PlanMassage:
            return formatToK(
                order.orderPlanDragonMassageSnapshot.totalAmount -
                    order.orderPlanDragonMassageSnapshot.prePaymentAmount,
            )
        case OrderType.PlanTutor:
            return formatToK(order.orderPlanTutorSnapshot.totalAmount - order.orderPlanTutorSnapshot.prePaymentAmount)
        default:
            return 'N/A'
    }
}
const PaymentTypeTexts: Record<PaymentType, string> = {
    [PaymentType.ECPAY_PAYMENT]: '綠界付款',
    [PaymentType.VOIN_PAYMENT]: 'VCoin',
}
const PaymentStatusTexts: Record<PaymentStatus, string> = {
    [PaymentStatus.INITIAL]: '未付款',
    [PaymentStatus.COMPLETED]: '付款成功',
    [PaymentStatus.FAILED]: '付款失敗',
    [PaymentStatus.EXPIRED]: '付款逾期',
    [PaymentStatus.REFUND]: '退款',
}
const paymentStatusColors: Record<PaymentStatus, string> = {
    [PaymentStatus.INITIAL]: 'warning',
    [PaymentStatus.COMPLETED]: 'success',
    [PaymentStatus.FAILED]: 'danger',
    [PaymentStatus.EXPIRED]: 'secondary',
    [PaymentStatus.REFUND]: 'warning',
}
const paymentLabel = (payment: Payment) => {
    const type = PaymentTypeTexts[payment.type]
    const status = PaymentStatusTexts[payment.status]
    return `${type} - ${status}`
}
const myOrders = computed(() => {
    // return orders.value
    return orders.value.map((order) => {
        if (order.type === ServiceCategoryBackend.ESCORT) {
            return {
                ...order,
                planName: planIdNameMap[order.orderPlanEscort.planId],
                startTime: `${getServiceDate(order)}\n${getServiceDuring(order)}`,
                orderPlanEscort: {
                    ...order.orderPlanEscort,
                },
            }
        }
        if (order.type === ServiceCategoryBackend.SHUTTLE)
            return {
                ...order,
                planName: shuttlePlanIdNameMap[order.orderPlanShuttle.planId],
                startTime: formatDateTimeV(Number(order.orderPlanShuttle.time)),
                orderPlanEscort: {
                    ...order.orderPlanShuttle,
                },
            }
        if (order.type === ServiceCategoryBackend.CHARTER)
            return {
                ...order,
                planName: '包車旅遊',
                startTime: formatDateTimeV(Number(order.orderPlanCharter.time)),
                orderPlanEscort: {
                    ...order.orderPlanCharter,
                },
            }
        if (order.type === ServiceCategoryBackend.MASSAGE) {
            let startTime = formatDateTimeV(Number(order.orderPlanDragonMassage.time))
            if (order.orderPlanDragonMassage.confirmedTime)
                startTime = formatDateTimeV(Number(order.orderPlanDragonMassage.confirmedTime))
            return {
                ...order,
                planName: '龍筋按摩',
                startTime,
                orderPlanEscort: {
                    ...order.orderPlanDragonMassage,
                },
            }
        }
        if (order.type === ServiceCategoryBackend.TUTOR) {
            const startTime = formatDateTimeV(Number(order.orderPlanTutor.startTime))
            return {
                ...order,
                planName: '越語家教',
                startTime,
                orderPlanEscort: {
                    ...order.orderPlanTutor,
                },
            }
        }
        if (order.type === ServiceCategoryBackend.QUOTE) {
            return {
                ...order,
                planName: '自訂訂單',
                startTime: 'N/A',
                orderPlanEscort: {
                    ...order.orderPlanCustomQuote,
                },
            }
        }
    })
})
</script>
<template>
    <VaDataTable
        v-model:sort-by="sortByVModel"
        v-model:sorting-order="sortingOrderVModel"
        :columns="columns"
        :items="myOrders"
        :loading="$props.loading"
    >
        <template #cell(id)="{ rowData }">
            <div class="flex items-center gap-2 max-w-[230px] ellipsis">
                {{ rowData.id }}
            </div>
        </template>

        <template #cell(username)="{ rowData }">
            <div class="max-w-[120px] ellipsis">{{ rowData.userInfo?.firstName }}</div>
        </template>

        <template #cell(status)="{ rowData }">
            <div class="ellipsis max-w-[230px]">
                <VaBadge
                    :text="statusTexts[rowData.status as OrderStatus]"
                    :color="statusColors[rowData.status as OrderStatus]"
                />
            </div>
        </template>
        <template #cell(payment)="{ rowData }">
            <div class="ellipsis max-w-[230px]">
                <VaBadge
                    v-for="payment in rowData.payment"
                    :key="payment.id"
                    :text="paymentLabel(payment as Payment)"
                    :color="paymentStatusColors[payment.status as PaymentStatus]"
                />
            </div>
        </template>
        <template #cell(manualOperationStatus)="{ rowData }">
            <div class="ellipsis max-w-[230px]">
                <VaBadge
                    :text="manualOperationStatusTexts[rowData.manualOperationStatus as OrderManualOperationStatus]"
                    :color="manualOperationStatusColors[rowData.manualOperationStatus as OrderManualOperationStatus]"
                />
            </div>
        </template>
        <template #cell(createdAt)="{ rowData }">
            <div class="ellipsis max-w-[230px]">
                {{ formatDateTime(Number(rowData.createdAt)) }}
            </div>
        </template>
        <template #cell(type)="{ rowData }">
            <div class="ellipsis max-w-[230px]">
                {{ categorys[rowData.type as ServiceCategoryBackend] }}
            </div>
        </template>

        <template #cell(planName)="{ rowData }">
            <div class="ellipsis max-w-[230px]">
                {{ rowData.planName }}
            </div>
        </template>
        <template #cell(startTime)="{ rowData }">
            <div class="max-w-[180px] ellipsis">
                {{ rowData.startTime }}
            </div>
        </template>
        <template #cell(numGuides)="{ rowData }">
            <div class="ellipsis max-w-[230px]">
                {{ rowData.orderPlanEscort?.numGuides }}
            </div>
        </template>
        <template #cell(attendant)="{}">
            <div class="ellipsis max-w-[230px]">服務人員</div>
        </template>
        <template #cell(deposit)="{ rowData }">
            <div class="ellipsis max-w-[230px]">{{ getDepositAmount(rowData) }}</div>
        </template>
        <template #cell(finalPayment)="{ rowData }">
            <div class="ellipsis max-w-[230px]">{{ getFinalPayment(rowData) }}</div>
        </template>

        <template #cell(role)="{ rowData }">
            <VaBadge :text="rowData.status" :color="statusColors[rowData.status as OrderStatus]" />
        </template>

        <template #cell(actions)="{ rowData }">
            <div class="flex gap-2 justify-end">
                <VaButton
                    preset="primary"
                    size="small"
                    icon="mso-edit"
                    aria-label="Edit user"
                    @click="$emit('edit-order', rowData as Order)"
                />
                <VaButton
                    preset="primary"
                    size="small"
                    icon="mso-delete"
                    color="danger"
                    aria-label="Delete user"
                    @click="onUserDelete(rowData as Order)"
                />
            </div>
        </template>
    </VaDataTable>

    <div class="flex flex-col-reverse md:flex-row gap-2 justify-between items-center py-2">
        <div>
            <b>共{{ $props.pagination.total }} 筆資料</b>
            每頁筆數
            <VaSelect v-model="$props.pagination.perPage" class="!w-20" :options="[10]" />
        </div>

        <div v-if="totalPages > 1" class="flex">
            <VaButton
                preset="secondary"
                icon="va-arrow-left"
                aria-label="Previous page"
                :disabled="$props.pagination.page === 1"
                @click="$props.pagination.page--"
            />
            <VaButton
                class="mr-2"
                preset="secondary"
                icon="va-arrow-right"
                aria-label="Next page"
                :disabled="$props.pagination.page === totalPages"
                @click="$props.pagination.page++"
            />
            <VaPagination
                v-model="$props.pagination.page"
                buttons-preset="secondary"
                :pages="totalPages"
                :visible-pages="5"
                :boundary-links="false"
                :direction-links="false"
            />
        </div>
    </div>
</template>

<style lang="scss" scoped>
.va-data-table {
    ::v-deep(.va-data-table__table-tr) {
        border-bottom: 1px solid var(--va-background-border);
    }
}
</style>
