<script setup lang="ts">
import { PropType, computed, onMounted } from 'vue'
import { ShuttleOrder } from '../types'
import { useFormat } from '../../../composables/useFormat'
import { useOrders } from '../composables/useOrders'
import { useShuttleOrders } from '../composables/useShuttleOrders'
import { useToast } from 'vuestic-ui'
import { OrderManualOperationStatus } from '../types'
import api from '../../../services/api'
const { notify } = useToast()
const { formatDate } = useFormat()
const { categorys } = useOrders()
const { getStartTime } = useShuttleOrders()
const planIdNameMap: { [key in number]: string } = {
    1: '接機',
    2: '送機',
}
const carIdToNameMap: { [key in number]: string } = {
    1: '經濟五座',
    2: '尊爵五座',
    3: '經濟七座',
    4: '商務七座',
    5: '尊爵七座',
    6: '商務九座',
    7: '多人巴士',
}
const areaIdToNameMap: { [key in number]: string } = {
    1: '1郡/3郡/富潤郡/新平郡',
    2: '7郡/守德市',
    3: '4郡/5郡/10郡/平盛郡',
    4: '其他郡（6郡/8郡/11郡/12郡/平新郡/舊邑郡/新富郡）',
}
const manualOperationStatus = [
    {
        text: '待處理',
        value: OrderManualOperationStatus.PENDING,
    },
    {
        text: '已處理',
        value: OrderManualOperationStatus.PROCESSED,
    },
]
const props = defineProps({
    order: {
        type: Object as PropType<ShuttleOrder>,
        required: true,
    },
    saveButtonLabel: {
        type: String,
        default: 'Save',
    },
})

const defaultOrder = {
    id: -1,
    manualOperationStatus: OrderManualOperationStatus.PENDING,
    createdAt: '',
    category: '',
    planId: -1,
    plan: '',
    cardName: '',
    areaName: '',
    serviceDate: '',
    serviceDuring: '',
    buyFastPass: '',
    passengerNumber: 0,
    passengerName: '',
    largeLuggageAmount: 0,
    smallLuggageAmount: 0,
    flightNumber: '',
    flightArrivalTime: '',
    flightType: '',
    customLocation: '',
    hotelName: '',
    note: '',
}

const order = computed(() => {
    if (!props.order) {
        return defaultOrder
    }
    const createdAt = formatDate(Number(props.order.orderPlanShuttle.createdAt))

    return {
        id: props.order.id,
        manualOperationStatus: props.order.manualOperationStatus,
        createdAt,
        category: categorys[props.order.type],
        planId: props.order.orderPlanShuttle.planId,
        plan: planIdNameMap[props.order.orderPlanShuttle.planId],
        cardName: carIdToNameMap[props.order.orderPlanShuttle.carId],
        areaName: areaIdToNameMap[props.order.orderPlanShuttle.areaId],
        serviceDate: formatDate(Number(props.order.orderPlanShuttle.time)),
        serviceDuring: getStartTime(props.order),
        buyFastPass: props.order.orderPlanShuttle.buyFastPass ? '是' : '否',
        passengerNumber: props.order.orderPlanShuttle.passengerNumber,
        passengerName: props.order.orderPlanShuttle.passengerName,
        largeLuggageAmount: props.order.orderPlanShuttle.largeLuggageAmount,
        smallLuggageAmount: props.order.orderPlanShuttle.smallLuggageAmount,
        flightNumber: props.order.orderPlanShuttle.flightNumber,
        flightArrivalTime: props.order.orderPlanShuttle.flightArrivalTime,
        flightType: props.order.orderPlanShuttle.flightType === 'international' ? '國際線' : '國內線',
        customLocation: props.order.orderPlanShuttle.customLocation,
        hotelName: props.order.orderPlanShuttle.hotelName,
        note: props.order.orderPlanShuttle.note,
    }
})
const userInfo = computed(() => {
    const lineId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'line')?.accountId
    const wechatId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'wechat')?.accountId
    const telegramId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'telegram')
        ?.accountId
    const zaloId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'zalo')?.accountId
    return {
        firstName: props.order.userInfo.firstName,
        email: props.order.userInfo.email,
        phone: props.order.userInfo.phone?.phoneNumber,
        phoneCode: props.order.userInfo.phone?.code,
        lineId,
        wechatId,
        telegramId,
        zaloId,
    }
})
const emit = defineEmits(['close', 'save'])

const onSave = async () => {
    // 只處理操作參數
    api.updateManualOperationStatus({
        orderId: props.order.id,
        manualOperationStatus: order.value.manualOperationStatus,
    })
    emit('save')
}
const isArrival = computed(() => {
    return order.value.planId === 1
})
onMounted(() => {})
const copyText = async (copyContent: string | undefined) => {
    if (!copyContent) {
        return
    }
    try {
        await navigator.clipboard.writeText(copyContent)
        notify({
            message: `已複製到剪貼簿: ${copyContent}`,
            duration: 3000,
        })
    } catch (err) {
        alert(`Failed to copy text: ${err}`)
    }
}
</script>

<template>
    <VaForm
        v-slot="{ isValid }"
        ref="add-user-form"
        class="flex-col justify-start items-start gap-4 inline-flex w-full"
    >
        <div class="self-stretch flex-col justify-start items-start gap-4 flex">
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單資訊</span></VaDivider>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.id"
                    label="訂單編號"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.createdAt"
                    label="下訂時間"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.category"
                    label="訂購項目"
                    class="w-full sm:w-1/2"
                    name="category"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.plan"
                    label="訂購方案"
                    class="w-full sm:w-1/2"
                    name="plan"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.cardName"
                    label="車款"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.areaName"
                    label="接送區域"
                    class="w-full sm:w-1/2"
                    name="serviceDuring"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.serviceDate"
                    label="行程日期"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.serviceDuring"
                    label="起始時間"
                    class="w-full sm:w-1/2"
                    name="serviceDuring"
                    readonly
                    preset="solid"
                />
            </div>
            <!-- <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.buyFastPass"
                    label="加購快速通關"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
            </div> -->
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.passengerNumber"
                    label="乘客人數"
                    class="w-full sm:w-1/2"
                    name="passengerNumber"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.passengerName"
                    :label="isArrival ? '舉牌大名' : '乘客姓名'"
                    class="w-full sm:w-1/2"
                    name="passengerName"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.largeLuggageAmount"
                    label="大行李"
                    class="w-full sm:w-1/2"
                    name="largeLuggageAmount"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.smallLuggageAmount"
                    label="小行李"
                    class="w-full sm:w-1/2"
                    name="smallLuggageAmount"
                    readonly
                    preset="solid"
                />
            </div>
            <div v-if="isArrival" class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.flightNumber"
                    label="航班編號"
                    class="w-full sm:w-1/2"
                    name="flightNumber"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.flightArrivalTime"
                    label="航班抵達時間"
                    class="w-full sm:w-1/2"
                    name="flightArrivalTime"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.flightType"
                    :label="isArrival ? '航班類別' : '下車地點'"
                    class="w-full sm:w-1/2"
                    name="flightType"
                    readonly
                    preset="solid"
                />
            </div>
            <VaTextarea
                v-model="order.customLocation"
                :label="isArrival ? '下車地點' : '上車地點'"
                class="w-full"
                name="customLocation"
                readonly
                preset="solid"
            />
            <VaTextarea
                v-model="order.hotelName"
                label="飯店名稱"
                class="w-full"
                name="hotelName"
                readonly
                preset="solid"
            />
            <VaTextarea v-model="order.note" label="訂單備註" class="w-full" name="note" readonly preset="solid" />

            <VaDivider class="w-full" orientation="left"><span class="px-2">聯絡資訊</span></VaDivider>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="userInfo.firstName"
                    label="訂購人"
                    class="w-full sm:w-1/2"
                    name="firstName"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="userInfo.email"
                    label="連絡信箱"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                >
                    <template #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.email)" />
                    </template>
                </VaInput>
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="userInfo.phoneCode"
                    label="手機國碼"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="userInfo.phone"
                    label="手機號碼"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                >
                    <template #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.phone)" />
                    </template>
                </VaInput>
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="userInfo.lineId"
                    label="Line ID"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                >
                    <template v-if="userInfo.lineId" #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.lineId)" />
                    </template>
                </VaInput>
                <VaInput
                    v-model="userInfo.wechatId"
                    label="WECHAT ID"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                >
                    <template v-if="userInfo.wechatId" #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.wechatId)" />
                    </template>
                </VaInput>
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="userInfo.telegramId"
                    label="TELEGRAM"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                >
                    <template v-if="userInfo.telegramId" #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.telegramId)" />
                    </template>
                </VaInput>
                <VaInput
                    v-model="userInfo.zaloId"
                    label="ZALO"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                >
                    <template v-if="userInfo.zaloId" #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.zaloId)" />
                    </template>
                </VaInput>
            </div>
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單狀態</span></VaDivider>
            <VaSelect
                v-model="order.manualOperationStatus"
                label="操作狀態"
                class="w-full"
                :options="manualOperationStatus"
                name="projects"
                text-by="text"
                track-by="value"
                value-by="value"
            />
            <VaDivider class="w-full" orientation="left"><span class="px-2">結帳資訊</span></VaDivider>
            <div class="flex gap-2 flex-col-reverse items-stretch justify-end w-full sm:flex-row sm:items-center">
                <VaButton preset="secondary" color="secondary" @click="$emit('close')">取消</VaButton>
                <VaButton :disabled="!isValid" @click="onSave">{{ saveButtonLabel }}</VaButton>
            </div>
        </div>
    </VaForm>
</template>
