import { CharterOrder } from '../types'
import { DateTime } from 'luxon'

export const useCharterOrders = () => {
    const getStartTime = (order: CharterOrder) => {
        const startTime = DateTime.fromMillis(Number(order.orderPlanCharter.time), { zone: 'Asia/Ho_Chi_Minh' })
        return startTime.toFormat('HH:mm')
    }

    return {
        getStartTime,
    }
}
