<script setup lang="ts">
import { PropType, computed, onMounted, ref } from 'vue'
import { Teacher, TutorOrder } from '../types'
import { usePublicStore } from '../../../stores/public-store'
import { useFormat } from '../../../composables/useFormat'
import { useOrders } from '../composables/useOrders'
import { useTutorOrders } from '../composables/useTutorOrders'
import { useToast } from 'vuestic-ui'
import { OrderManualOperationStatus } from '../types'
import api from '../../../services/api'
const { notify } = useToast()
const { formatDate, formatDateV } = useFormat()
const { categorys } = useOrders()
const { getStartTime, teacherConfirm } = useTutorOrders()
const publicStore = usePublicStore()
const planIdNameMap: { [key in number]: string } = {
    1: '越語家教',
}
const manualOperationStatus = [
    {
        text: '待處理',
        value: OrderManualOperationStatus.PENDING,
    },
    {
        text: '已處理',
        value: OrderManualOperationStatus.PROCESSED,
    },
]
const props = defineProps({
    order: {
        type: Object as PropType<TutorOrder>,
        required: true,
    },
    saveButtonLabel: {
        type: String,
        default: 'Save',
    },
})

const defaultOrder = {
    id: -1,
    createdAt: '',
    category: '',
    plan: '',
    serviceDate: '',
    serviceStartTime: '',
    note: '',
    hotelAddress: '',
    needHotelBooking: '',
    manualOperationStatus: OrderManualOperationStatus.PENDING,
    hotelImageUrls: [] as string[],
    confirmedTeacherId: null,
    selectedTeachers: '',
}

const order = computed(() => {
    if (!props.order) {
        return defaultOrder
    }
    const createdAt = formatDate(Number(props.order.orderPlanTutor.createdAt))

    return {
        id: props.order.id,
        manualOperationStatus: props.order.manualOperationStatus,
        createdAt,
        category: categorys[props.order.type],
        plan: planIdNameMap[props.order.orderPlanTutor.planId],
        selectedTeachers: getselectedTeachers(props.order.orderPlanTutor.teachers || []),
        serviceDate: formatDateV(Number(props.order.orderPlanTutor.startTime)),
        serviceStartTime: getStartTime(props.order),
        hotelAddress: props.order.orderPlanTutor.address,
        confirmedTeacherId: props.order.orderPlanTutor.confirmedTeacherId || null,
    }
})
const getselectedTeachers = (teachers: Teacher[]) => {
    return teachers
        .map((teacher) => {
            return `${teacher.number}`
        })
        .join(', ')
}
const userInfo = computed(() => {
    const lineId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'line')?.accountId
    const wechatId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'wechat')?.accountId
    const telegramId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'telegram')
        ?.accountId
    const zaloId = props.order.userInfo.socialMedia.find((socialMedia) => socialMedia.type === 'zalo')?.accountId
    return {
        firstName: props.order.userInfo.firstName,
        email: props.order.userInfo.email,
        phone: props.order.userInfo.phone?.phoneNumber,
        phoneCode: props.order.userInfo.phone?.code,
        lineId,
        wechatId,
        telegramId,
        zaloId,
    }
})
const emit = defineEmits(['close', 'save'])

const onSave = async () => {
    // 處理操作參數
    if (props.order.manualOperationStatus !== order.value.manualOperationStatus) {
        await api.updateManualOperationStatus({
            orderId: props.order.id,
            manualOperationStatus: order.value.manualOperationStatus,
        })
    }
    if (props.order.orderPlanTutor.confirmedTeacherId !== confirmedTeacherId.value) {
        if (!confirmedTeacherId.value) {
            return
        }
        await teacherConfirm({
            orderId: props.order.id,
            teacherId: confirmedTeacherId.value,
        })
    }

    emit('save')
}

onMounted(() => {
    // 初始化已確認的老師ID
    confirmedTeacherId.value = order.value.confirmedTeacherId || null
})
const copyText = async (copyContent: string | undefined) => {
    if (!copyContent) {
        return
    }
    try {
        await navigator.clipboard.writeText(copyContent)
        notify({
            message: `已複製到剪貼簿: ${copyContent}`,
            duration: 3000,
        })
    } catch (err) {
        alert(`Failed to copy text: ${err}`)
    }
}

const teachers = computed(() => {
    return publicStore.teachers
        .filter((teacher) => teacher.isActive)
        .map((teacher) => ({
            text: `${teacher.number}`,
            value: teacher.id,
        }))
})
const confirmedTeacherId = ref<number | null>(null)
</script>

<template>
    <VaForm
        v-slot="{ isValid }"
        ref="add-user-form"
        class="flex-col justify-start items-start gap-4 inline-flex w-full"
    >
        <div class="self-stretch flex-col justify-start items-start gap-4 flex">
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單資訊</span></VaDivider>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.id"
                    label="訂單編號"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.createdAt"
                    label="下訂時間"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.category"
                    label="訂購項目"
                    class="w-full sm:w-1/2"
                    name="category"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.plan"
                    label="訂購方案"
                    class="w-full sm:w-1/2"
                    name="plan"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.serviceDate"
                    label="預約日期"
                    class="w-full sm:w-1/2"
                    name="fullname"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="order.serviceStartTime"
                    label="起始時間"
                    class="w-full sm:w-1/2"
                    name="serviceStartTime"
                    readonly
                    preset="solid"
                />
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="order.selectedTeachers"
                    label="老師偏好"
                    class="w-full"
                    name="guideExpect"
                    readonly
                    preset="solid"
                />
            </div>
            <VaTextarea
                v-model="order.hotelAddress"
                label="上課地址"
                class="w-full"
                name="customLocation"
                readonly
                preset="solid"
            />
            <VaDivider class="w-full" orientation="left"><span class="px-2">管理確認區</span></VaDivider>
            <div class="w-full">
                <VaSelect
                    v-model="confirmedTeacherId"
                    label="家教老師指派"
                    class="w-full"
                    :options="teachers"
                    name="projects"
                    text-by="text"
                    track-by="value"
                    value-by="value"
                    placeholder="未指派"
                />
            </div>
            <VaDivider class="w-full" orientation="left"><span class="px-2">訂單狀態</span></VaDivider>
            <VaSelect
                v-model="order.manualOperationStatus"
                label="操作狀態"
                class="w-full"
                :options="manualOperationStatus"
                name="projects"
                text-by="text"
                track-by="value"
                value-by="value"
            />
            <VaDivider class="w-full" orientation="left"><span class="px-2">聯絡資訊</span></VaDivider>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="userInfo.firstName"
                    label="訂購人"
                    class="w-full sm:w-1/2"
                    name="firstName"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="userInfo.email"
                    label="連絡信箱"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                >
                    <template #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.email)" />
                    </template>
                </VaInput>
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="userInfo.phoneCode"
                    label="手機國碼"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                />
                <VaInput
                    v-model="userInfo.phone"
                    label="手機號碼"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                >
                    <template #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.phone)" />
                    </template>
                </VaInput>
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="userInfo.lineId"
                    label="Line ID"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                >
                    <template v-if="userInfo.lineId" #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.lineId)" />
                    </template>
                </VaInput>
                <VaInput
                    v-model="userInfo.wechatId"
                    label="WECHAT ID"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                >
                    <template v-if="userInfo.wechatId" #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.wechatId)" />
                    </template>
                </VaInput>
            </div>
            <div class="flex gap-4 flex-col sm:flex-row w-full">
                <VaInput
                    v-model="userInfo.telegramId"
                    label="TELEGRAM"
                    class="w-full sm:w-1/2"
                    name="id"
                    readonly
                    preset="solid"
                >
                    <template v-if="userInfo.telegramId" #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.telegramId)" />
                    </template>
                </VaInput>
                <VaInput
                    v-model="userInfo.zaloId"
                    label="ZALO"
                    class="w-full sm:w-1/2"
                    name="createdAt"
                    readonly
                    preset="solid"
                >
                    <template v-if="userInfo.zaloId" #appendInner>
                        <VaIcon name="content_copy" color="secondary" @click="() => copyText(userInfo.zaloId)" />
                    </template>
                </VaInput>
            </div>
            <VaDivider class="w-full" orientation="left"><span class="px-2">結帳資訊</span></VaDivider>
            <div class="flex gap-2 flex-col-reverse items-stretch justify-end w-full sm:flex-row sm:items-center">
                <VaButton preset="secondary" color="secondary" @click="$emit('close')">取消</VaButton>
                <VaButton :disabled="!isValid" @click="onSave">{{ saveButtonLabel }}</VaButton>
            </div>
        </div>
    </VaForm>
</template>
